CREATE TABLE countries ( id INTEGER NOT NULL, name VARCHAR NOT NULL, CONSTRAINT app_countries_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS app_countries_id_seq INCREMENT 1 START 21 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY countries.id;
CREATE TABLE states ( id INTEGER NOT NULL, country_id INTEGER NOT NULL, name VARCHAR NOT NULL, CONSTRAINT app_states_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS app_states_id_seq INCREMENT 1 START 74 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY states.id;
